// CollectorDetailPage collects data and returns the collector detail page component.
func CollectorDetailPage(ctx context.Context, c *collector.DataCollector, h *collector.DataHistory, name string, basePath string) (templ.Component, error) {
	detail := c.CollectCollectorDetail(ctx, name)
	if detail == nil {
		return ErrorPage(404, "Not Found", "Collector '"+name+"' not found", basePath), nil
	}

	metricsData := c.CollectMetrics(ctx)
	entries := collectorMetricEntries(detail.Metrics)

	// Build HTTP-specific charts
	var statusChart, methodChart chart.Data
	if name == "http" {
		statusChart = buildStatusCodeChartData(detail.Metrics)
		methodChart = buildMethodChartData(detail.Metrics)
	}

	return CollectorDetailPageContent(detail, metricsData, entries, statusChart, methodChart, basePath), nil
}

